module.exports = function(RED) {
    "use strict";

    function NeuralConv2DNode(n) {
        RED.nodes.createNode(this, n);
        var node = this;
        node.filters = n.filters || 4;
        node.kernelSize = n.kernelSize || 3;
        node.activation = n.activation || "none";
        node.inputChannels = n.inputChannels || 1;

        node.kernels = n.kernels || null;

        node.on("input", function(msg, send, done) {
            var input = msg.payload;
            if (!Array.isArray(input)) {
                input = [input];
            }

            if (!node.kernels) {
                node.kernels = [];
                for (var f = 0; f < node.filters; f++) {
                    node.kernels[f] = [];
                    var klen = node.kernelSize * node.kernelSize * node.inputChannels;
                    for (var i = 0; i < klen; i++) {
                        node.kernels[f][i] = Math.random() * 2 - 1;
                    }
                }
                node.bias = Array(node.filters).fill(0).map(function() { return Math.random() * 0.4 - 0.2; });
            }

            var output = [];
            for (var f = 0; f < node.filters; f++) {
                var sum = node.bias[f];
                for (var i = 0; i < input.length; i++) {
                    var ki = i % node.kernels[f].length;
                    sum += node.kernels[f][ki] * (input[i] || 0);
                }
                if (node.activation === "relu") sum = Math.max(0, sum);
                else if (node.activation === "sigmoid") sum = 1 / (1 + Math.exp(-sum));
                output.push(sum);
            }

            msg.payload = output;
            msg.neural = msg.neural || {};
            msg.neural.type = "conv2d";
            msg.neural.shape = [output.length];

            var active = output.filter(function(v) { return v > 0; }).length;
            node.status({ fill: active > 0 ? "blue" : "grey", shape: "dot", text: node.filters + " filters" });

            send(msg);
            done();
        });
    }

    RED.nodes.registerType("neural-conv2d", NeuralConv2DNode);
};
